const data = msg.payload || {};

function processAddressPortFields(input) {
    const processed = { ...input };
    const fields = [
        { field: 'gateway_ip_port', addressField: 'gateway_ip', portField: 'gateway_port' },
        { field: 'mqttadresse_port', addressField: 'mqttadresse', portField: 'mqttport' }
    ];

    for (const cfg of fields) {
        const value = processed[cfg.field];
        if (typeof value === 'string' && value.includes(':')) {
            const lastColonIndex = value.lastIndexOf(':');
            processed[cfg.addressField] = value.substring(0, lastColonIndex);
            processed[cfg.portField] = parseInt(value.substring(lastColonIndex + 1), 10);
            delete processed[cfg.field];
        }
    }

    return processed;
}

function defaultStandardFeatures() {
    return {
        mqtt_core: true,
        ha_discovery: true,
        bank_core: true,
        pack_core: true,
        basic_alerts: true,
        influxdb: false,
        grafana: false,
        csv_export: false,
        cycles_soh: false,
        cell_details: false,
        advanced_info: false
    };
}

try {
    const cfg = processAddressPortFields(data);

    global.set('addon_config', cfg);

    if (cfg.pylontech_path) global.set('path', cfg.pylontech_path);
    global.set('use_gateway', !!cfg.use_gateway);

    if (cfg.gateway_ip !== undefined) global.set('gateway_ip', cfg.gateway_ip);
    if (cfg.gateway_port !== undefined) global.set('gateway_port', cfg.gateway_port);

    global.set('communication_debug', !!cfg.communication_debug);

    if (cfg.mqttadresse) global.set('mqttadresse', cfg.mqttadresse);
    if (cfg.mqttport !== undefined) global.set('mqttport', cfg.mqttport);

    global.set('mqttuser', cfg.mqttuser || '');
    global.set('mqttpass', cfg.mqttpass || '');
    global.set('mqtt_client_id', cfg.mqtt_client_id || 'nodered_pylontech');
    global.set('mqtt_base_topic', cfg.mqtt_base_topic || 'pylontech1');

    global.set('Send_bip', cfg.Send_bip !== undefined ? !!cfg.Send_bip : true);
    global.set('sp_csv_output_dir', cfg.csv_output_dir || '/share/pylontech');
    global.set('premium_debug', !!cfg.premium_debug);
    global.set('premium_barcode_hint', cfg.premium_barcode_hint || '');

    // Premium : on stocke seulement la clé brute ici
    const premiumKey = String(cfg.premium_license || '').trim();
    global.set('premium.key', premiumKey);

    // Valeurs par défaut avant validation réelle
    global.set('premium.active', false);
    global.set('premium.status', premiumKey ? 'pending_validation' : 'missing');
    global.set('premium.tier', 'standard');
    global.set('premium.features', defaultStandardFeatures());
    global.set('premium.product', 'smartphoton-pylontech');
    global.set('premium.system', 'pylontech_rs232');

    // Compat avec les anciens nœuds
    global.set('premium_enabled', false);
    global.set('sp_license', {
        valid: false,
        tier: 'standard',
        product: 'smartphoton-pylontech',
        license_id: null,
        customer: null,
        issued_at: null,
        bound_to: null,
        error: premiumKey ? 'pending_validation' : 'missing_or_invalid_license',
        features: defaultStandardFeatures()
    });

    flow.set('pylon_base', cfg.mqtt_base_topic || 'pylontech1');

    msg.payload = {
        status: 'success',
        message: 'Variables globales créées avec succès',
        variables: {
            path: global.get('path'),
            use_gateway: global.get('use_gateway'),
            gateway_ip: global.get('gateway_ip'),
            gateway_port: global.get('gateway_port'),
            communication_debug: global.get('communication_debug'),
            mqttadresse: global.get('mqttadresse'),
            mqttport: global.get('mqttport'),
            mqttuser: global.get('mqttuser'),
            mqtt_client_id: global.get('mqtt_client_id'),
            mqtt_base_topic: global.get('mqtt_base_topic'),
            csv_output_dir: global.get('sp_csv_output_dir'),
            premium_key_present: premiumKey !== '',
            premium_status: global.get('premium.status')
        }
    };
} catch (error) {
    node.error('Erreur lors de la création des variables globales: ' + error.message, msg);
    msg.payload = { status: 'error', message: error.message };
}

msg._init = 'config_loaded';

const msgSerial = RED.util.cloneMessage(msg);
msgSerial._init = 'serial_apply';

const msgMqtt = RED.util.cloneMessage(msg);
msgMqtt._init = 'mqtt_connect';

const msgPremium = RED.util.cloneMessage(msg);
msgPremium._init = 'premium_init';

return [msg, msgSerial, msgMqtt, msgPremium];

msg.payload = {
    serialport: global.get('path'),
    serialbaud: 115200,
    databits: 8,
    parity: 'none',
    stopbits: 1,
    enabled: true
};
return msg;

msg.action = 'connect';
msg.broker = JSON.stringify({
    broker: global.get('mqttadresse'),
    port: String(global.get('mqttport') || 1883),
    username: global.get('mqttuser') || '',
    password: global.get('mqttpass') || ''
});
return msg;

const installId =
    String(env.get('PYLONTECH_RS232_INSTALL_ID') || '').trim() ||
    String(env.get('SMARTPHOTON_INSTALL_ID') || '').trim();

const premiumKey = String(global.get('premium.key') || '').trim();

if (!installId) {

    node.status({
        fill: "red",
        shape: "ring",
        text: "install_id missing"
    });

    return null;
}

flow.set('premium_install_id', installId, 'persistent');

global.set('premium.install_id', installId);

global.set('premium.active', false);
global.set('premium.status', premiumKey ? 'pending_validation' : 'missing');
global.set('premium.tier', 'standard');

global.set('premium.product', 'smartphoton-pylontech');
global.set('premium.system', 'pylontech_rs232');

if (!global.get('premium.features')) {

    global.set('premium.features', {
        mqtt_core: true,
        ha_discovery: true,
        bank_core: true,
        pack_core: true,
        basic_alerts: true,
        influxdb: false,
        grafana: false,
        csv_export: false,
        cycles_soh: false,
        cell_details: false,
        advanced_info: false
    });

}

node.status({

    fill: "green",
    shape: "dot",
    text: "install " + installId.slice(0, 8)

});

msg.payload = {

    install_id: installId,
    premium_key_present: premiumKey !== '',
    premium_status: global.get('premium.status')

};

return msg;

const crypto = global.get('crypto') || require('crypto');

const LICENSE_SECRET = "SVP_2026_9f7c2e51b4d84f38a1e9c7b6d5e4f301_ULTRA_LONG_SECRET";

function defaultStandardFeatures() {
    return {
        mqtt_core: true,
        ha_discovery: true,
        bank_core: true,
        pack_core: true,
        basic_alerts: true,
        influxdb: false,
        grafana: false,
        csv_export: false,
        cycles_soh: false,
        cell_details: false,
        advanced_info: false
    };
}

function defaultPremiumFeatures() {
    return {
        mqtt_core: true,
        ha_discovery: true,
        bank_core: true,
        pack_core: true,
        basic_alerts: true,
        influxdb: true,
        grafana: true,
        csv_export: true,
        cycles_soh: true,
        cell_details: true,
        advanced_info: true
    };
}

function signInstallId(installId) {
    return crypto
        .createHmac("sha256", LICENSE_SECRET)
        .update(String(installId))
        .digest("hex");
}

const premiumKey = String(global.get("premium.key") || "").trim();

const installId =
    String(global.get("premium.install_id") || "").trim() ||
    String(flow.get("premium_install_id", "persistent") || "").trim();

let active = false;
let status = "missing";
let tier = "standard";
let features = defaultStandardFeatures();

const lic = {
    valid: false,
    tier: "standard",
    product: "smartphoton-pylontech",
    license_id: null,
    customer: null,
    issued_at: null,
    bound_to: installId || null,
    error: "missing_or_invalid_license",
    features
};

if (!premiumKey) {
    status = "missing";
} else {
    try {
        const parts = premiumKey.split("|");

        if (parts.length !== 4) throw new Error("invalid_format");

        const prefix = String(parts[0] || "").trim();
        const keyTier = String(parts[1] || "").trim();
        const keyInstallId = String(parts[2] || "").trim();
        const signature = String(parts[3] || "").trim();

        if (prefix !== "SVP") throw new Error("invalid_prefix");
        if (keyTier !== "premium") throw new Error("invalid_tier");
        if (!installId) throw new Error("missing_install_id");
        if (keyInstallId !== installId) throw new Error("install_id_mismatch");

        const expected = signInstallId(keyInstallId);

        if (signature.toLowerCase() !== expected.toLowerCase()) {
            throw new Error("invalid_signature");
        }

        active = true;
        status = "active";
        tier = "premium";
        features = defaultPremiumFeatures();

        lic.valid = true;
        lic.tier = tier;
        lic.error = null;
        lic.features = features;
    } catch (e) {
        status = e.message || "invalid_license";
        active = false;
        tier = "standard";
        features = defaultStandardFeatures();

        lic.error = status;
        lic.features = features;
    }
}

global.set("premium.install_id", installId);
global.set("premium.active", active);
global.set("premium.status", status);
global.set("premium.tier", tier);
global.set("premium.features", features);
global.set("premium.product", "smartphoton-pylontech");
global.set("premium.system", "pylontech_rs232");

global.set("premium_enabled", active);
global.set("sp_license", lic);

node.status({
    fill: active ? "green" : "yellow",
    shape: "dot",
    text: active ? `Premium active ${installId.slice(0, 8)}...` : `Premium ${status}`
});

msg.payload = {
    premium_install_id: installId,
    premium_active: active ? "ON" : "OFF",
    premium_status: status,
    premium_tier: tier,
    premium_product: "smartphoton-pylontech",
    premium_system: "pylontech_rs232"
};

return msg;

const BASE = flow.get('pylon_base') || 'pylontech1';
const MAX_ADDR = 15;
const now = Date.now();

flow.set('pylon_need_discovery', true);
flow.set('pylon_detecting', true);
flow.set('pylon_detect_started_at', now);
flow.set('pylon_boot_at', flow.get('pylon_boot_at') || now);

let meta = flow.get('pylon_meta') || {};
meta.packs = meta.packs || 0;
meta.cells = meta.cells || 0;
meta.highest_ok = 0;
meta.highest_confirmed = Number(meta.highest_confirmed) || 0;
meta.detect_started_at = now;
delete meta.first_not_present_idx;
flow.set('pylon_meta', meta);

const queue = [];
// Always enter debug mode first (read-only use)
queue.push({ kind:'dbg', index:0, cmd:'login debug' });
queue.push({ kind:'info', index:1, cmd:'info 1' });
for (let i=1;i<=MAX_ADDR;i++) queue.push({ kind:'stat', index:i, cmd:`stat ${i}` });

flow.set('pylon_queue', queue);
flow.set('pylon_busy', false);
flow.set('pylon_rx_buf', '');
flow.set('pylon_last_task', null);
flow.set('pylon_stat_active', null);
flow.set('pylon_expect_stat', null);
return { payload:true };

const BASE = flow.get('pylon_base') || 'pylontech1';
let meta = flow.get('pylon_meta') || {};
const packs = Number(meta.packs) || 0;
if (packs <= 0) return null;

const tasks = [];
for (let i=1;i<=packs;i++) tasks.push({ kind:'pwr', index:i, cmd:`pwr ${i}` });
msg.payload = tasks;
return msg;

const BASE = flow.get('pylon_base') || 'pylontech1';
let meta = flow.get('pylon_meta') || {};
const packs = Number(meta.packs) || 0;
if (packs <= 0) return null;

const tasks = [];
for (let i=1;i<=packs;i++) tasks.push({ kind:'bat', index:i, cmd:`bat ${i}` });
msg.payload = tasks;
return msg;

const BASE = flow.get('pylon_base') || 'pylontech1';
const MAX_ADDR = 15;
const tasks = [];
for (let i=1;i<=MAX_ADDR;i++) tasks.push({ kind:'stat', index:i, cmd:`stat ${i}` });
msg.payload = tasks;
return msg;

const BASE = flow.get('pylon_base') || 'pylontech1';
// Build INFO queue: info 1..packs
let meta = flow.get('pylon_meta') || {};
const packs = Number(meta.packs) || 0;
if (packs <= 0) return null;

const tasks = [];
for (let i = 1; i <= packs; i++) {
  tasks.push({ kind: 'info', index: i, cmd: `info ${i}` });
}
msg.payload = tasks;
return msg;

const BASE = flow.get('pylon_base') || 'pylontech1';
const add = msg.payload;
if (!Array.isArray(add) || add.length === 0) return null;

let q = flow.get('pylon_queue') || [];
q = q.concat(add);

const MAX_Q = 500;
if (q.length > MAX_Q) q = q.slice(q.length - MAX_Q);

flow.set('pylon_queue', q);
return { payload: true };

const BASE = flow.get('pylon_base') || 'pylontech1';
const busy = flow.get('pylon_busy') || false;
if (busy) return null;

const queue = flow.get('pylon_queue') || [];

if (queue.length === 0) {
  const need = flow.get('pylon_need_discovery') || false;
  const meta = flow.get('pylon_meta') || {};
  if (need && meta.packs > 0 && meta.cells > 0) {
    flow.set('pylon_need_discovery', false);
    flow.set('pylon_detecting', false);
    meta.detect_done_at = Date.now();
    flow.set('pylon_meta', meta);
    return [null, { payload:true }];
  }
  return null;
}

const task = queue.shift();
flow.set('pylon_queue', queue);

flow.set('pylon_busy', true);
flow.set('pylon_last_task', task);
flow.set('pylon_last_serial_tx', Date.now());

// Track active STAT command to handle fragmented console output reliably
if (task.kind === 'stat') {
  flow.set('pylon_stat_active', { index: task.index, buffer: '', until: Date.now() + 15000 });
}
// Remember the last STAT index for fragmented responses
if (task.kind === 'stat') {
  flow.set('pylon_expect_stat', { index: task.index, until: Date.now() + 8000 });
}
return [{ payload: task.cmd + "\n" }, null];

const BASE = flow.get('pylon_base') || 'pylontech1';
const now = Date.now();

let buf = flow.get('pylon_rx_buf') || '';
buf += (msg.payload || '');
flow.set('pylon_rx_buf', buf);
flow.set('pylon_last_serial_rx', now);

if (!buf.includes('$$')) return null;

const idx = buf.indexOf('$$');
const frame = buf.slice(0, idx);
flow.set('pylon_rx_buf', buf.slice(idx + 2));

msg.payload = frame
  .replace(/pylon(?:_debug)?>[^\n]*\n/g, '\n')
  .replace(/^@\s*\n/mg, '\n')
  .trim();

msg._task_snapshot = flow.get('pylon_last_task') || null;
flow.set('pylon_busy', false);
flow.set('pylon_last_frame_ok', now);
return msg;

const BASE = flow.get('pylon_base') || 'pylontech1';
const task = msg._task_snapshot || flow.get('pylon_last_task') || {};
const text = String(msg.payload || '');

const invalid = /Invalid command|fail to excute/i.test(text);
const notPresent = /Target device is not present/i.test(text);

msg._task = task;
msg._invalid = invalid;
msg._notPresent = notPresent;

if (task.kind === 'dbg') return null;
if (task.kind === 'info') return [msg, null, null, null];
if (task.kind === 'stat') return [null, msg, null, null];
if (task.kind === 'pwr')  return [null, null, msg, null];
if (task.kind === 'bat')  return [null, null, null, msg];
return null;

const BASE = flow.get('pylon_base') || 'pylontech1';
// Parse info n -> meta.cells + publish pack info on MQTT
const task = msg._task || {};
const index = Number(task.index || 1);
const nn = String(index).padStart(2, '0');
const now = Date.now();

if (msg._invalid || msg._notPresent) return null;

const lic = global.get('sp_license') || {};
const hasAdvancedInfo = !!(lic.features && lic.features.advanced_info);

const text = String(msg.payload || '');
let meta = flow.get('pylon_meta') || {};
let packs = flow.get('pylon_packs') || {};
let p = packs[nn] || {};

function pick(re) {
  const m = text.match(re);
  return m ? String(m[1]).trim() : null;
}
function pickNum(re) {
  const v = pick(re);
  if (v == null) return null;
  const n = Number(String(v).replace(/[^\d\-]/g, ''));
  return Number.isFinite(n) ? n : null;
}

const fullInfo = {
  device_address: pick(/Device\s+address\s*:\s*([^\r\n]+)/i),
  manufacturer:   pick(/Manufacturer\s*:\s*([^\r\n]+)/i),
  device_name:    pick(/Device\s+name\s*:\s*([^\r\n]+)/i),
  board_version:  pick(/Board\s+version\s*:\s*([^\r\n]+)/i),
  board:          pick(/Board\s*:\s*([^\r\n]+)/i),
  main_soft:      pick(/Main\s+Soft\s+version\s*:\s*([^\r\n]+)/i),
  soft_version:   pick(/Soft\s+version\s*:\s*([^\r\n]+)/i),
  boot_version:   pick(/Boot\s+version\s*:\s*([^\r\n]+)/i),
  comm_version:   pick(/Comm\s+version\s*:\s*([^\r\n]+)/i),
  release_date:   pick(/Release\s+Date\s*:\s*([^\r\n]+)/i),
  barcode:        pick(/Barcode\s*:\s*([^\r\n]+)/i),
  specification:  pick(/Specification\s*:\s*([^\r\n]+)/i),
  cell_number:    pickNum(/Cell\s+Number\s*:\s*(\d+)/i),
  max_dischg_mA:  pickNum(/Max\s+Dischg\s+Curr\s*:\s*([-\d]+)\s*mA/i),
  max_charge_mA:  pickNum(/Max\s+Charge\s+Curr\s*:\s*([-\d]+)\s*mA/i),
  epon_baud:      pickNum(/EPONPort\s+rate\s*:\s*(\d+)/i),
  console_baud:   pickNum(/Console\s+Port\s+rate\s*:\s*(\d+)/i),
  last_seen: now
};

const publicInfo = hasAdvancedInfo ? fullInfo : {
  manufacturer: fullInfo.manufacturer,
  device_name: fullInfo.device_name,
  cell_number: fullInfo.cell_number,
  last_seen: now
};

// meta global (utile pour auto-discovery)
if (index === 1) {
  if (fullInfo.cell_number) meta.cells = fullInfo.cell_number;
  if (fullInfo.device_name) meta.device_name = fullInfo.device_name;
}
const confirmed = !!(fullInfo.device_name || fullInfo.barcode || fullInfo.cell_number);
if (confirmed) {
  if (!meta.confirmed_present || typeof meta.confirmed_present !== 'object') meta.confirmed_present = {};
  meta.confirmed_present[nn] = now;
  meta.highest_confirmed = Math.max(Number(meta.highest_confirmed) || 0, index);
  flow.set('pylon_last_data_seen', now);
}
flow.set('pylon_meta', meta);

// stocke dans le pack
p.info_last_seen = now;
p.info = publicInfo;
p.info_full = fullInfo;
packs[nn] = p;
flow.set('pylon_packs', packs);

// publie le JSON info sur un topic dédié
return {
  topic: `${BASE}/battery/${nn}/info`,
  payload: publicInfo,
  retain: true
};

const detecting = flow.get('pylon_detecting') || false;
if (!detecting) return null;

const task = msg._task || {};
const idx = Number(task.index) || 0;
const text = String(msg.payload || '');

let meta = flow.get('pylon_meta') || {};
meta.highest_ok = Number(meta.highest_ok) || 0;

const plausibleStat =
  !msg._notPresent &&
  !msg._invalid &&
  text.length >= 80 &&
  /(CYCLE\s*Times|SOH\s*:|Command completed successfully|Basic\s+Status|Current\s+Status|Volt\s+Status|Tmpr\.|Coul\.|Heater\s+Status)/i.test(text);

if (plausibleStat && idx > meta.highest_ok) {
  meta.highest_ok = idx;
}

if (msg._notPresent && !meta.first_not_present_idx) {
  meta.first_not_present_idx = idx;
  if (meta.highest_ok > 0) meta.packs = meta.highest_ok;
}

// Fallback in case all queried addresses looked "present"
if (!msg._notPresent && idx >= 15 && meta.highest_ok > 0 && !meta.packs) {
  meta.packs = meta.highest_ok;
}

flow.set('pylon_meta', meta);
return null;

const BASE = flow.get('pylon_base') || 'pylontech1';
const task = msg._task || {};
const index = task.index || 1;
const nn = String(index).padStart(2,'00');
const now = Date.now();

if (msg._invalid) return null;

const text = String(msg.payload);

function pickNum(re){ const m = text.match(re); return m ? Number(m[1]) : null; }
function pickStr(re){ const m = text.match(re); return m ? String(m[1]).trim() : null; }

let packs = flow.get('pylon_packs') || {};
let p = packs[nn] || {};

const v_mV = pickNum(/Voltage\s*:\s*(\d+)\s*mV/i);
const i_mA = pickNum(/Current\s*:\s*(-?\d+)\s*mA/i);
const t_mC = pickNum(/Temperature\s*:\s*(\d+)\s*mC/i);
const soc  = pickNum(/Coulomb\s*:\s*(\d+)\s*%/i);

const cycles = pickNum(/CYCLE\s*Times\s*:\s*(\d+)/i);
const soh    = pickNum(/SOH\s*:\s*(\d+)\s*%?/i);
if (cycles !== null) p.cycles = cycles;
if (soh    !== null) p.soh    = soh;

if (v_mV !== null) p.voltage = Math.round((v_mV/1000)*1000)/1000;
if (i_mA !== null) p.current = Math.round((i_mA/1000)*1000)/1000;
if (p.voltage != null && p.current != null) p.power = Math.round((p.voltage*p.current)*1000)/1000;
if (t_mC !== null) p.temp = Math.round((t_mC/1000)*10)/10;
if (soc  !== null) p.soc  = soc;

p.basic_status   = pickStr(/Basic\s+Status\s*:\s*([^\r\n]+)/i)   || p.basic_status   || null;
p.volt_status    = pickStr(/Volt\s+Status\s*:\s*([^\r\n]+)/i)    || p.volt_status    || null;
p.current_status = pickStr(/Current\s+Status\s*:\s*([^\r\n]+)/i) || p.current_status || null;
p.tmpr_status    = pickStr(/Tmpr\.\s+Status\s*:\s*([^\r\n]+)/i)  || p.tmpr_status    || null;
p.coul_status    = pickStr(/Coul\.\s+Status\s*:\s*([^\r\n]+)/i)  || p.coul_status    || null;
p.soh_status     = pickStr(/Soh\.\s+Status\s*:\s*([^\r\n]+)/i)   || p.soh_status     || null;
p.heater_status  = pickStr(/Heater\s+Status\s*:\s*([^\r\n]+)/i)  || p.heater_status  || null;

p.last_seen = now;
packs[nn] = p;
flow.set('pylon_packs', packs);

// ── PROMOTION GLOBAL (lecture depuis tab Premium) ──
global.set('pylon_packs', packs);

const confirmed = [v_mV, i_mA, t_mC, soc].some(v => v !== null);
let meta = flow.get('pylon_meta') || {};
if (confirmed) {
  if (!meta.confirmed_present || typeof meta.confirmed_present !== 'object') meta.confirmed_present = {};
  meta.confirmed_present[nn] = now;
  meta.highest_confirmed = Math.max(Number(meta.highest_confirmed) || 0, index);
  flow.set('pylon_meta', meta);
  flow.set('pylon_last_data_seen', now);
  // Promouvoir aussi meta
  global.set('pylon_meta', meta);
}

return { topic:`${BASE}/battery/${nn}/state`, payload:p, retain:true };

const BASE = flow.get('pylon_base') || 'pylontech1';
const task = msg._task || {};
const index = task.index || 1;
const nnPack = String(index).padStart(2,'0');
const now = Date.now();

if (msg._invalid) return null;

const lic = global.get('sp_license') || {};
const hasCellDetails = !!(lic.features && lic.features.cell_details);

const meta = flow.get('pylon_meta') || {};
const CELL_COUNT = Number(meta.cells) || 15;

const text = String(msg.payload);
const lines = text.split(/\r?\n/).map(l=>l.trim()).filter(Boolean);

let cellsByPack = flow.get('pylon_cells') || {};
if (!cellsByPack[nnPack]) cellsByPack[nnPack] = {};

const out = [];
const vlist_mV = [];

for (const l of lines) {
  const parts = l.split(/\s+/);
  const idx = Number(parts[0]);
  if (!Number.isFinite(idx)) continue;
  if (idx < 0 || idx >= CELL_COUNT) continue;

  const cellNo = idx + 1;
  const nnCell = String(cellNo).padStart(2,'0');

  const volt_mV = Number(parts[1]);
  const curr_mA = Number(parts[2]);
  const temp_mC = Number(parts[3]);

  const base_state = parts[4] || null;
  const volt_state = parts[5] || null;
  const curr_state = parts[6] || null;
  const temp_state = parts[7] || null;

  if (Number.isFinite(volt_mV)) vlist_mV.push(volt_mV);

  const payload = {
    voltage: Number.isFinite(volt_mV) ? Math.round((volt_mV/1000)*1000)/1000 : null,
    current: Number.isFinite(curr_mA) ? Math.round((curr_mA/1000)*1000)/1000 : null,
    temp:    Number.isFinite(temp_mC) ? Math.round((temp_mC/1000)*10)/10 : null,
    base_state,
    volt_state,
    curr_state,
    temp_state,
    last_seen: now
  };

  cellsByPack[nnPack][nnCell] = payload;

  if (hasCellDetails) {
    out.push({ topic:`${BASE}/battery/${nnPack}/cell/${nnCell}/state`, payload, retain:true });
  }
}

flow.set('pylon_cells', cellsByPack);

let packs = flow.get('pylon_packs') || {};
let p = packs[nnPack] || {};

if (vlist_mV.length > 0) {
  const vmin = Math.min(...vlist_mV);
  const vmax = Math.max(...vlist_mV);

  p.cell_v_min = Math.round((vmin/1000)*1000)/1000;
  p.cell_v_max = Math.round((vmax/1000)*1000)/1000;
  p.cell_delta_mv = vmax - vmin;
  p.cell_delta_v = Math.round(((vmax-vmin)/1000)*1000)/1000;
}

p.last_cells = now;
packs[nnPack] = p;
flow.set('pylon_packs', packs);

const confirmed = vlist_mV.length > 0;
let meta2 = flow.get('pylon_meta') || {};
if (confirmed) {
  if (!meta2.confirmed_present || typeof meta2.confirmed_present !== 'object') meta2.confirmed_present = {};
  meta2.confirmed_present[nnPack] = now;
  meta2.highest_confirmed = Math.max(Number(meta2.highest_confirmed) || 0, index);
  flow.set('pylon_meta', meta2);
  flow.set('pylon_last_data_seen', now);
}

out.unshift({ topic:`${BASE}/battery/${nnPack}/state`, payload:p, retain:true });
return [out];

const BASE = flow.get('pylon_base') || 'pylontech1';
const now = Date.now();
const timeoutMs = 2 * 60 * 1000;

const premiumActive = global.get('premium.active') === true;

// Bank = premium only
if (!premiumActive) {

  flow.set('pylon_bank', null);
  global.set('pylon_bank', null);

  // efface retained MQTT
  return {
    topic: `${BASE}/bank/state`,
    payload: "",
    retain: true
  };
}

const meta = flow.get('pylon_meta') || {};
const packsMax = Number(meta.packs) || 0;

if (packsMax <= 0) return null;

const packs = flow.get('pylon_packs') || {};

const socs = [];

let online = 0;
let totalPower = 0;
let totalCurrent = 0;
let totalVoltage = 0;
let voltageCount = 0;

for (let i = 1; i <= packsMax; i++) {

  const nn = String(i).padStart(2, '0');

  const p = packs[nn];

  if (!p) continue;

  if ((now - (p.last_seen || 0)) > timeoutMs) continue;

  online++;

  if (Number.isFinite(p.soc))
    socs.push(p.soc);

  if (Number.isFinite(p.power))
    totalPower += p.power;

  if (Number.isFinite(p.current))
    totalCurrent += p.current;

  if (Number.isFinite(p.voltage)) {

    totalVoltage += p.voltage;
    voltageCount++;

  }
}

let bank = {};

bank.packs_present = packsMax;
bank.packs_online = online;

// Power → entier
bank.power_total = Math.round(totalPower);

// Current → 2 décimales
bank.current_total =
  Math.round(totalCurrent * 100) / 100;

// Average voltage → 2 décimales
if (voltageCount > 0) {

  bank.voltage_avg =
    Math.round((totalVoltage / voltageCount) * 100) / 100;

}

// SOC stats
if (socs.length > 0) {

  const avg =
    socs.reduce((a, b) => a + b, 0) / socs.length;

  // SOC avg → 1 décimale
  bank.soc_avg =
    Math.round(avg * 10) / 10;

  bank.soc_min =
    Math.min(...socs);

  bank.soc_max =
    Math.max(...socs);

}

bank.last_agg = now;

flow.set('pylon_bank', bank);

// promotion globale premium
global.set('pylon_bank', bank);

return {

  topic: `${BASE}/bank/state`,
  payload: bank,
  retain: true

};

const BASE = flow.get('pylon_base') || 'pylontech1';
const meta = flow.get('pylon_meta') || {};
const PACKS_MAX = Number(meta.packs) || 0;
const CELLS = Number(meta.cells) || 0;

if (PACKS_MAX <= 0 || CELLS <= 0) return null;

const premiumActive = global.get('premium.active') === true;
const lic = global.get('sp_license') || {};
const features = lic.features || {};

const hasCellDetails = premiumActive && !!features.cell_details;
const hasAdvancedInfo = premiumActive && !!features.advanced_info;
const hasCyclesSoh = premiumActive && !!features.cycles_soh;

const manufacturer = "Smartphoton / ©JLM 2026";
const sw = "3.1";
const modelPack = "Pylontech US2000c / US3000 / US5000 / Pelio";

function publish(topic, payload) {
  return { topic, payload, retain: true };
}

function drop(topic) {
  return { topic, payload: "", retain: true };
}

function sensorCfg(object_id, name, state_topic, value_template, unit, device_class, state_class, device, entity_category) {
  const cfg = {
    name,
    unique_id: `${BASE}_${object_id}`,
    state_topic,
    value_template,
    availability_topic: `${BASE}/status`,
    payload_available: "online",
    payload_not_available: "offline",
    device
  };

  if (unit) cfg.unit_of_measurement = unit;
  if (device_class) cfg.device_class = device_class;
  if (state_class) cfg.state_class = state_class;
  if (entity_category) cfg.entity_category = entity_category;

  // --------------------------------------------------
  // Precision rules
  // --------------------------------------------------
  // Average voltage = 2 decimals
  if (object_id === "pylontech_bank_voltage_avg") {
    cfg.suggested_display_precision = 2;
  }

  // All cell voltages / cell min/max / cell delta V = 3 decimals
  if (
    object_id.includes("cell") &&
    (
      object_id.includes("voltage") ||
      object_id.includes("cell_v_min") ||
      object_id.includes("cell_v_max") ||
      object_id.includes("cell_delta_v") ||
      /cell_\d+_voltage/.test(object_id)
    )
  ) {
    cfg.suggested_display_precision = 3;
  }

  return cfg;
}

function packConfigTopics(nn, cells) {
  const topics = [
    `homeassistant/sensor/pylontech_batt_${nn}_voltage/config`,
    `homeassistant/sensor/pylontech_batt_${nn}_current/config`,
    `homeassistant/sensor/pylontech_batt_${nn}_power/config`,
    `homeassistant/sensor/pylontech_batt_${nn}_temp/config`,
    `homeassistant/sensor/pylontech_batt_${nn}_soc/config`,
    `homeassistant/sensor/pylontech_batt_${nn}_cell_v_min/config`,
    `homeassistant/sensor/pylontech_batt_${nn}_cell_v_max/config`,
    `homeassistant/sensor/pylontech_batt_${nn}_cell_delta_mv/config`,
    `homeassistant/sensor/pylontech_batt_${nn}_cell_delta_v/config`,

    `homeassistant/sensor/pylontech_batt_${nn}_device_name/config`,
    `homeassistant/sensor/pylontech_batt_${nn}_barcode/config`,
    `homeassistant/sensor/pylontech_batt_${nn}_release_date/config`,
    `homeassistant/sensor/pylontech_batt_${nn}_board_version/config`,
    `homeassistant/sensor/pylontech_batt_${nn}_board/config`,
    `homeassistant/sensor/pylontech_batt_${nn}_main_soft/config`,
    `homeassistant/sensor/pylontech_batt_${nn}_soft_version/config`,
    `homeassistant/sensor/pylontech_batt_${nn}_boot_version/config`,
    `homeassistant/sensor/pylontech_batt_${nn}_comm_version/config`,
    `homeassistant/sensor/pylontech_batt_${nn}_spec/config`,
    `homeassistant/sensor/pylontech_batt_${nn}_max_charge/config`,
    `homeassistant/sensor/pylontech_batt_${nn}_max_discharge/config`,
    `homeassistant/sensor/pylontech_batt_${nn}_epon_baud/config`,
    `homeassistant/sensor/pylontech_batt_${nn}_console_baud/config`,
    `homeassistant/sensor/pylontech_batt_${nn}_cycles/config`,
    `homeassistant/sensor/pylontech_batt_${nn}_soh/config`
  ];

  for (let c = 1; c <= cells; c++) {
    const cc = String(c).padStart(2, '0');
    topics.push(
      `homeassistant/sensor/pylontech_batt_${nn}_cell_${cc}_voltage/config`,
      `homeassistant/sensor/pylontech_batt_${nn}_cell_${cc}_temp/config`
    );
  }

  return topics;
}

const out = [];

// --------------------------------------------------
// Cleanup retained discovery when premium features disappear
// --------------------------------------------------
const prevPacks = Number(flow.get('pylon_discovery_packs') || 0);
const prevCells = Number(flow.get('pylon_discovery_cells') || CELLS);
const prevFeatures = flow.get('pylon_discovery_features') || {};
const cleanupCells = Math.max(prevCells, CELLS);

for (let i = PACKS_MAX + 1; i <= prevPacks; i++) {
  const nn = String(i).padStart(2, '0');
  for (const topic of packConfigTopics(nn, cleanupCells)) {
    out.push(drop(topic));
  }
}

if (prevFeatures.bank_sensors && !premiumActive) {
  out.push(drop(`homeassistant/sensor/pylontech_bank_packs_present/config`));
  out.push(drop(`homeassistant/sensor/pylontech_bank_packs_online/config`));
  out.push(drop(`homeassistant/sensor/pylontech_bank_soc_avg/config`));
  out.push(drop(`homeassistant/sensor/pylontech_bank_soc_min/config`));
  out.push(drop(`homeassistant/sensor/pylontech_bank_soc_max/config`));
  out.push(drop(`homeassistant/sensor/pylontech_bank_power_total/config`));
  out.push(drop(`homeassistant/sensor/pylontech_bank_current_total/config`));
  out.push(drop(`homeassistant/sensor/pylontech_bank_voltage_avg/config`));
}

if (prevFeatures.advanced_info && !hasAdvancedInfo) {
  for (let i = 1; i <= PACKS_MAX; i++) {
    const nn = String(i).padStart(2, '0');
    for (const topic of [
      `homeassistant/sensor/pylontech_batt_${nn}_device_name/config`,
      `homeassistant/sensor/pylontech_batt_${nn}_barcode/config`,
      `homeassistant/sensor/pylontech_batt_${nn}_release_date/config`,
      `homeassistant/sensor/pylontech_batt_${nn}_board_version/config`,
      `homeassistant/sensor/pylontech_batt_${nn}_board/config`,
      `homeassistant/sensor/pylontech_batt_${nn}_main_soft/config`,
      `homeassistant/sensor/pylontech_batt_${nn}_soft_version/config`,
      `homeassistant/sensor/pylontech_batt_${nn}_boot_version/config`,
      `homeassistant/sensor/pylontech_batt_${nn}_comm_version/config`,
      `homeassistant/sensor/pylontech_batt_${nn}_spec/config`,
      `homeassistant/sensor/pylontech_batt_${nn}_max_charge/config`,
      `homeassistant/sensor/pylontech_batt_${nn}_max_discharge/config`,
      `homeassistant/sensor/pylontech_batt_${nn}_epon_baud/config`,
      `homeassistant/sensor/pylontech_batt_${nn}_console_baud/config`
    ]) {
      out.push(drop(topic));
    }
  }
}

if (prevFeatures.cycles_soh && !hasCyclesSoh) {
  for (let i = 1; i <= PACKS_MAX; i++) {
    const nn = String(i).padStart(2, '0');
    out.push(drop(`homeassistant/sensor/pylontech_batt_${nn}_cycles/config`));
    out.push(drop(`homeassistant/sensor/pylontech_batt_${nn}_soh/config`));
  }
}

if (prevFeatures.cell_details && !hasCellDetails) {
  for (let i = 1; i <= PACKS_MAX; i++) {
    const nn = String(i).padStart(2, '0');
    for (let c = 1; c <= cleanupCells; c++) {
      const cc = String(c).padStart(2, '0');
      out.push(drop(`homeassistant/sensor/pylontech_batt_${nn}_cell_${cc}_voltage/config`));
      out.push(drop(`homeassistant/sensor/pylontech_batt_${nn}_cell_${cc}_temp/config`));
    }
  }
}

// --------------------------------------------------
// Premium-only bank device + sensors
// --------------------------------------------------
if (premiumActive) {
  const devBank = {
    identifiers: [`${BASE}_battery_bank`],
    name: "Pylontech Battery Bank",
    manufacturer,
    model: `Bank – ${PACKS_MAX} packs`,
    sw_version: sw
  };

  out.push(publish("homeassistant/sensor/pylontech_bank_packs_present/config",
    sensorCfg("pylontech_bank_packs_present", "Packs present", `${BASE}/bank/state`, "{{ value_json.packs_present }}", null, null, "measurement", devBank)));

  out.push(publish("homeassistant/sensor/pylontech_bank_packs_online/config",
    sensorCfg("pylontech_bank_packs_online", "Packs online", `${BASE}/bank/state`, "{{ value_json.packs_online }}", null, null, "measurement", devBank)));

  out.push(publish("homeassistant/sensor/pylontech_bank_soc_avg/config",
    sensorCfg("pylontech_bank_soc_avg", "SOC average", `${BASE}/bank/state`, "{{ value_json.soc_avg }}", "%", "battery", "measurement", devBank)));

  out.push(publish("homeassistant/sensor/pylontech_bank_soc_min/config",
    sensorCfg("pylontech_bank_soc_min", "SOC min", `${BASE}/bank/state`, "{{ value_json.soc_min }}", "%", "battery", "measurement", devBank)));

  out.push(publish("homeassistant/sensor/pylontech_bank_soc_max/config",
    sensorCfg("pylontech_bank_soc_max", "SOC max", `${BASE}/bank/state`, "{{ value_json.soc_max }}", "%", "battery", "measurement", devBank)));

  out.push(publish("homeassistant/sensor/pylontech_bank_power_total/config",
    sensorCfg("pylontech_bank_power_total", "Total power", `${BASE}/bank/state`, "{{ value_json.power_total }}", "W", "power", "measurement", devBank)));

  out.push(publish("homeassistant/sensor/pylontech_bank_current_total/config",
    sensorCfg("pylontech_bank_current_total", "Total current", `${BASE}/bank/state`, "{{ value_json.current_total }}", "A", "current", "measurement", devBank)));

  out.push(publish("homeassistant/sensor/pylontech_bank_voltage_avg/config",
    sensorCfg("pylontech_bank_voltage_avg", "Average voltage", `${BASE}/bank/state`, "{{ value_json.voltage_avg | float | round(2) }}", "V", "voltage", "measurement", devBank)));
}

// --------------------------------------------------
// Pack sensors
// --------------------------------------------------
for (let i = 1; i <= PACKS_MAX; i++) {
  const nn = String(i).padStart(2, '0');

  const devPack = {
    identifiers: [`${BASE}_battery_${nn}`],
    name: `Pylontech Battery ${i}`,
    manufacturer,
    model: modelPack,
    sw_version: sw
  };

  if (premiumActive) {
    devPack.via_device = `${BASE}_battery_bank`;
  }

  const stPack = `${BASE}/battery/${nn}/state`;

  // PREMIUM advanced info
  if (hasAdvancedInfo) {
    const stInfo = `${BASE}/battery/${nn}/info`;

    out.push(publish(`homeassistant/sensor/pylontech_batt_${nn}_device_name/config`,
      sensorCfg(`pylontech_batt_${nn}_device_name`, `Device name`, stInfo, "{{ value_json.device_name }}", null, null, null, devPack, "diagnostic")));

    out.push(publish(`homeassistant/sensor/pylontech_batt_${nn}_barcode/config`,
      sensorCfg(`pylontech_batt_${nn}_barcode`, `Barcode`, stInfo, "{{ value_json.barcode }}", null, null, null, devPack, "diagnostic")));

    out.push(publish(`homeassistant/sensor/pylontech_batt_${nn}_release_date/config`,
      sensorCfg(`pylontech_batt_${nn}_release_date`, `Release Date`, stInfo, "{{ value_json.release_date }}", null, null, null, devPack, "diagnostic")));

    out.push(publish(`homeassistant/sensor/pylontech_batt_${nn}_board_version/config`,
      sensorCfg(`pylontech_batt_${nn}_board_version`, `Board version`, stInfo, "{{ value_json.board_version }}", null, null, null, devPack, "diagnostic")));

    out.push(publish(`homeassistant/sensor/pylontech_batt_${nn}_board/config`,
      sensorCfg(`pylontech_batt_${nn}_board`, `Board`, stInfo, "{{ value_json.board }}", null, null, null, devPack, "diagnostic")));

    out.push(publish(`homeassistant/sensor/pylontech_batt_${nn}_main_soft/config`,
      sensorCfg(`pylontech_batt_${nn}_main_soft`, `Main soft`, stInfo, "{{ value_json.main_soft }}", null, null, null, devPack, "diagnostic")));

    out.push(publish(`homeassistant/sensor/pylontech_batt_${nn}_soft_version/config`,
      sensorCfg(`pylontech_batt_${nn}_soft_version`, `Soft version`, stInfo, "{{ value_json.soft_version }}", null, null, null, devPack, "diagnostic")));

    out.push(publish(`homeassistant/sensor/pylontech_batt_${nn}_boot_version/config`,
      sensorCfg(`pylontech_batt_${nn}_boot_version`, `Boot version`, stInfo, "{{ value_json.boot_version }}", null, null, null, devPack, "diagnostic")));

    out.push(publish(`homeassistant/sensor/pylontech_batt_${nn}_comm_version/config`,
      sensorCfg(`pylontech_batt_${nn}_comm_version`, `Comm version`, stInfo, "{{ value_json.comm_version }}", null, null, null, devPack, "diagnostic")));

    out.push(publish(`homeassistant/sensor/pylontech_batt_${nn}_spec/config`,
      sensorCfg(`pylontech_batt_${nn}_spec`, `Specification`, stInfo, "{{ value_json.specification }}", null, null, null, devPack, "diagnostic")));

    out.push(publish(`homeassistant/sensor/pylontech_batt_${nn}_max_charge/config`,
      sensorCfg(`pylontech_batt_${nn}_max_charge`, `Max charge current`, stInfo, "{{ value_json.max_charge_mA }}", "mA", null, "measurement", devPack, "diagnostic")));

    out.push(publish(`homeassistant/sensor/pylontech_batt_${nn}_max_discharge/config`,
      sensorCfg(`pylontech_batt_${nn}_max_discharge`, `Max discharge current`, stInfo, "{{ value_json.max_dischg_mA }}", "mA", null, "measurement", devPack, "diagnostic")));

    out.push(publish(`homeassistant/sensor/pylontech_batt_${nn}_epon_baud/config`,
      sensorCfg(`pylontech_batt_${nn}_epon_baud`, `EPON baudrate`, stInfo, "{{ value_json.epon_baud }}", "bps", null, "measurement", devPack, "diagnostic")));

    out.push(publish(`homeassistant/sensor/pylontech_batt_${nn}_console_baud/config`,
      sensorCfg(`pylontech_batt_${nn}_console_baud`, `Console baudrate`, stInfo, "{{ value_json.console_baud }}", "bps", null, "measurement", devPack, "diagnostic")));
  }

  // FREE sensors
  out.push(publish(`homeassistant/sensor/pylontech_batt_${nn}_voltage/config`,
    sensorCfg(`pylontech_batt_${nn}_voltage`, `Voltage`, stPack, "{{ value_json.voltage | float | round(3) }}", "V", "voltage", "measurement", devPack)));

  out.push(publish(`homeassistant/sensor/pylontech_batt_${nn}_current/config`,
    sensorCfg(`pylontech_batt_${nn}_current`, `Current`, stPack, "{{ value_json.current }}", "A", "current", "measurement", devPack)));

  out.push(publish(`homeassistant/sensor/pylontech_batt_${nn}_power/config`,
    sensorCfg(`pylontech_batt_${nn}_power`, `Power`, stPack, "{{ value_json.power }}", "W", "power", "measurement", devPack)));

  out.push(publish(`homeassistant/sensor/pylontech_batt_${nn}_temp/config`,
    sensorCfg(`pylontech_batt_${nn}_temp`, `Temperature`, stPack, "{{ value_json.temp }}", "°C", "temperature", "measurement", devPack)));

  out.push(publish(`homeassistant/sensor/pylontech_batt_${nn}_soc/config`,
    sensorCfg(`pylontech_batt_${nn}_soc`, `SOC`, stPack, "{{ value_json.soc }}", "%", "battery", "measurement", devPack)));

  out.push(publish(`homeassistant/sensor/pylontech_batt_${nn}_cell_v_min/config`,
    sensorCfg(`pylontech_batt_${nn}_cell_v_min`, `Cell voltage min`, stPack, "{{ value_json.cell_v_min | float | round(3) }}", "V", "voltage", "measurement", devPack)));

  out.push(publish(`homeassistant/sensor/pylontech_batt_${nn}_cell_v_max/config`,
    sensorCfg(`pylontech_batt_${nn}_cell_v_max`, `Cell voltage max`, stPack, "{{ value_json.cell_v_max | float | round(3) }}", "V", "voltage", "measurement", devPack)));

  out.push(publish(`homeassistant/sensor/pylontech_batt_${nn}_cell_delta_mv/config`,
    sensorCfg(`pylontech_batt_${nn}_cell_delta_mv`, `Cell delta`, stPack, "{{ value_json.cell_delta_mv }}", "mV", null, "measurement", devPack)));

  out.push(publish(`homeassistant/sensor/pylontech_batt_${nn}_cell_delta_v/config`,
    sensorCfg(`pylontech_batt_${nn}_cell_delta_v`, `Cell delta V`, stPack, "{{ value_json.cell_delta_v | float | round(3) }}", "V", "voltage", "measurement", devPack)));

  // PREMIUM cycles / SOH
  if (hasCyclesSoh) {
    out.push(publish(`homeassistant/sensor/pylontech_batt_${nn}_cycles/config`,
      sensorCfg(`pylontech_batt_${nn}_cycles`, `Cycles`, stPack, "{{ value_json.cycles }}", null, null, "measurement", devPack, "diagnostic")));

    out.push(publish(`homeassistant/sensor/pylontech_batt_${nn}_soh/config`,
      sensorCfg(`pylontech_batt_${nn}_soh`, `SOH`, stPack, "{{ value_json.soh }}", "%", null, "measurement", devPack, "diagnostic")));
  }

  // PREMIUM cell details
  if (hasCellDetails) {
    for (let c = 1; c <= CELLS; c++) {
      const cc = String(c).padStart(2, '0');
      const stCell = `${BASE}/battery/${nn}/cell/${cc}/state`;

      out.push(publish(`homeassistant/sensor/pylontech_batt_${nn}_cell_${cc}_voltage/config`,
        sensorCfg(`pylontech_batt_${nn}_cell_${cc}_voltage`, `Cell ${c} Voltage`, stCell, "{{ value_json.voltage | float | round(3) }}", "V", "voltage", "measurement", devPack, "diagnostic")));

      out.push(publish(`homeassistant/sensor/pylontech_batt_${nn}_cell_${cc}_temp/config`,
        sensorCfg(`pylontech_batt_${nn}_cell_${cc}_temp`, `Cell ${c} Temp`, stCell, "{{ value_json.temp }}", "°C", "temperature", "measurement", devPack, "diagnostic")));
    }
  }
}

flow.set('pylon_discovery_packs', PACKS_MAX);
flow.set('pylon_discovery_cells', CELLS);
flow.set('pylon_discovery_features', {
  bank_sensors: premiumActive,
  cell_details: hasCellDetails,
  advanced_info: hasAdvancedInfo,
  cycles_soh: hasCyclesSoh
});

return [out];

const premiumActive = global.get('premium.active') === true;
const premiumFeatures = global.get('premium.features') || {};

if (!premiumActive || premiumFeatures.cycles_soh !== true) {
  return null;
}

const BASE = flow.get('pylon_base') || 'pylontech1';
const task = msg._task || msg._task_snapshot || {};
const index = Number(task.index || 1);
const nn = String(index).padStart(2, '0');
const now = Date.now();

if (msg._invalid || msg._notPresent) return null;

// Normalize incoming frame/chunk
let text = String(msg.payload || '');
text = text.replace(/[\u21B5\u2190-\u21FF]/g, ' ');

// STAT frames are typically complete (RX buffers until $$), but keep a small per-pack buffer just in case.
const key = `pylon_stat_buf_${nn}`;
let buf = flow.get(key) || '';
buf += "\n" + text;
if (buf.length > 12000) buf = buf.slice(-12000);

// Extract values
function pickNum(re) {
  const m = buf.match(re);
  return m ? Number(m[1]) : null;
}

const cycles = pickNum(/CYCLE\s*Times\s*:\s*(\d+)/i);
const soh = pickNum(/(?:^|\n)\s*SOH\s*:\s*(\d+)\s*%?/i);

if (cycles === null && soh === null) {
  flow.set(key, buf);
  return null;
}

// Update pack state store
let packs = flow.get('pylon_packs') || {};
let p = packs[nn] || {};

if (cycles !== null) p.cycles = cycles;
if (soh !== null) p.soh = soh;

p.last_seen = now;
packs[nn] = p;
flow.set('pylon_packs', packs);

// Clear buffer when command completed marker appears
if (/Command completed successfully|\$\$/.test(buf)) {
  flow.set(key, '');
} else {
  flow.set(key, buf);
}

// Publish to pack state topic (Discovery expects value_json.cycles/value_json.soh)
const dbg = {
  pack: nn,
  task_kind: task.kind || null,
  cycles_found: cycles,
  soh_found: soh,
  chunk_sample: String(text).slice(0, 200)
};

const msgDbg = {
  topic: `${BASE}/debug/stat/${nn}`,
  payload: dbg,
  retain: false
};

const msgState = {
  topic: `${BASE}/battery/${nn}/state`,
  payload: p,
  retain: true
};

return [msgState, msgDbg];

// ===== Build Latest State daily CSV from flow memory =====
const lic = global.get('sp_license') || {};
if (!(lic.features && lic.features.csv_export)) return null;

// Source:
//   - flow.pylon_packs
//   - flow.pylon_meta
//
// Output:
//   msg.filename = /share/pylontech/pylontech_latest_state_daily_YYYY-MM-DD.csv
//   msg.payload  = header (once/day) + 1 line per pack
//
// Notes:
// - No additional RS232 polling here.
// - Uses values already parsed by the main flow.
// - Semicolon separator for Excel.
// - Decimal comma for FR Excel compatibility.

const packs = flow.get('pylon_packs') || {};
const meta  = flow.get('pylon_meta') || {};
const count = Number(meta.packs) || 0;

if (count <= 0) return null;

function pad(n){ return String(n).padStart(2,'0'); }
function toFr(val, digits){
    if (val === null || val === undefined || val === '') return '';
    const num = Number(val);
    if (!Number.isFinite(num)) return '';
    return num.toFixed(digits).replace('.', ',');
}
function toInt(val){
    const num = Number(val);
    return Number.isFinite(num) ? String(Math.round(num)) : '';
}

const now = new Date();
const day = `${now.getFullYear()}-${pad(now.getMonth()+1)}-${pad(now.getDate())}`;
const stamp = `${day} ${pad(now.getHours())}:${pad(now.getMinutes())}:${pad(now.getSeconds())}`;

let lines = [];
const headerKey = `pylon_latest_state_header_written_${day}`;
const headerDone = flow.get(headerKey) || false;

if (!headerDone) {
    lines.push('sep=;');
    lines.push('Time;pack;SOC_pct;Voltage_V;Current_A;Power_W;Temp_C;Cell_min_V;Cell_max_V;Delta_cell_mV');
    flow.set(headerKey, true);
}

// Build one row per configured pack, even if some values are missing
for (let i = 1; i <= count; i++) {
    const nn = String(i).padStart(2,'0');
    const p = packs[nn] || {};

    lines.push([
        stamp,
        i,
        toFr(p.soc, 1),
        toFr(p.voltage, 2),
        toFr(p.current, 2),
        toInt(p.power),
        toFr(p.temp, 1),
        toFr(p.cell_v_min, 3),
        toFr(p.cell_v_max, 3),
        toInt(p.cell_delta_mv)
    ].join(';'));
}

const csvDir = global.get('sp_csv_output_dir') || '/share/pylontech';
msg.filename = `${csvDir.replace(/\/$/, '')}/pylontech_latest_state_daily_${day}.csv`;
msg.payload = lines.join('\n') + '\n';
return msg;

const BASE = flow.get('pylon_base') || 'pylontech1';
const now = Date.now();

const meta = flow.get('pylon_meta') || {};
const bank = flow.get('pylon_bank') || {};
const busy = !!flow.get('pylon_busy');
const detecting = !!flow.get('pylon_detecting');

const lastRx = Number(flow.get('pylon_last_serial_rx') || 0);
const lastTx = Number(flow.get('pylon_last_serial_tx') || 0);
const lastFrame = Number(flow.get('pylon_last_frame_ok') || 0);
const lastData = Number(flow.get('pylon_last_data_seen') || 0);
const lastAgg = Number(bank.last_agg || 0);
const lastReset = Number(flow.get('pylon_watchdog_last_reset') || 0);

let status = {
  ts: now,
  busy,
  detecting,
  queue_len: (flow.get('pylon_queue') || []).length,
  last_rx_age_s: lastRx ? Math.round((now - lastRx) / 1000) : null,
  last_tx_age_s: lastTx ? Math.round((now - lastTx) / 1000) : null,
  last_frame_age_s: lastFrame ? Math.round((now - lastFrame) / 1000) : null,
  last_data_age_s: lastData ? Math.round((now - lastData) / 1000) : null,
  packs_configured: Number(meta.packs) || 0,
  highest_confirmed: Number(meta.highest_confirmed) || 0,
  state: "ok"
};

let outStatus = { topic: `${BASE}/health/serial`, payload: status, retain: true };
let outRestart = null;
let outDiscovery = null;

// Clamp ghost pack count after a grace period once real traffic confirmed fewer packs
const packs = Number(meta.packs) || 0;
const highestConfirmed = Number(meta.highest_confirmed) || 0;
const detectDoneAt = Number(meta.detect_done_at || meta.detect_started_at || 0);
if (!detecting && packs > 0 && highestConfirmed > 0 && highestConfirmed < packs) {
  const graceMs = 90 * 1000;
  if (detectDoneAt > 0 && (now - detectDoneAt) >= graceMs) {
    meta.packs = highestConfirmed;
    meta.ghost_clamped_at = now;
    flow.set('pylon_meta', meta);
    status.state = "ghost_pack_clamped";
    status.packs_configured = meta.packs;
    outStatus = { topic: `${BASE}/health/serial`, payload: status, retain: true };
    outDiscovery = { payload: true };
  }
}

// Detect stalled serial path and soft recover without restarting Node-RED
const cooldownMs = 3 * 60 * 1000;
const busyTooLong = busy && lastTx && (now - lastTx) > 20 * 1000;
const noFramesTooLong = !detecting && lastFrame && (now - lastFrame) > 120 * 1000;
const noDataTooLong = !detecting && lastAgg && (now - lastAgg) > 120 * 1000;

if ((busyTooLong || noFramesTooLong || noDataTooLong) && (now - lastReset) > cooldownMs) {
  flow.set('pylon_busy', false);
  flow.set('pylon_queue', []);
  flow.set('pylon_rx_buf', '');
  flow.set('pylon_last_task', null);
  flow.set('pylon_stat_active', null);
  flow.set('pylon_expect_stat', null);
  flow.set('pylon_watchdog_last_reset', now);

  status.state = "serial_recovery_triggered";
  status.reason = busyTooLong ? "busy_timeout" : (noFramesTooLong ? "no_frame_timeout" : "no_data_timeout");
  outStatus = { topic: `${BASE}/health/serial`, payload: status, retain: true };
  outRestart = { payload: true };
}

return [outStatus, outRestart, outDiscovery];

const BASE = flow.get('pylon_base') || global.get('mqtt_base_topic') || 'pylontech1';
msg.topic = `${BASE}/status`;
msg.payload = 'online';
return msg;

const BASE = flow.get('pylon_base') || 'pylontech1';
const now = Date.now();

let buf = flow.get('pylon_rx_buf') || '';
buf += (msg.payload || '');
flow.set('pylon_rx_buf', buf);
flow.set('pylon_last_serial_rx', now);

if (!buf.includes('$$')) return null;

const idx = buf.indexOf('$$');
const frame = buf.slice(0, idx);
flow.set('pylon_rx_buf', buf.slice(idx + 2));

msg.payload = frame
  .replace(/pylon(?:_debug)?>[^\n]*\n/g, '\n')
  .replace(/^@\s*\n/mg, '\n')
  .trim();

msg._task_snapshot = flow.get('pylon_last_task') || null;
flow.set('pylon_busy', false);
flow.set('pylon_last_frame_ok', now);
return msg;

const base = String(global.get('mqtt_base_topic') || flow.get('pylon_base') || 'pylontech1');

const installId =
    String(global.get('premium.install_id') || '').trim() ||
