node.warn({
    premium_install_id_global: global.get('premium.install_id'),
    premium_install_id_persistent: flow.get('premium_install_id', 'persistent'),
    install_id_used: installId
});

msg.topic = `${base}/system/info`;
msg.payload = {
    install_id: installId,
    premium_active: global.get('premium.active') === true ? 'ON' : 'OFF',
    premium_status: String(global.get('premium.status') || 'missing'),
    premium_tier: String(global.get('premium.tier') || 'standard'),
    premium_product: String(global.get('premium.product') || 'smartphoton-pylontech'),
    premium_system: String(global.get('premium.system') || 'pylontech_rs232')
};

msg.retain = true;
msg.qos = 0;

return msg;

